from __future__ import annotations

import base64
import io
import os
import runpy
import sys
import tempfile
import zipfile
from pathlib import Path

BUNDLE_B64 = ''''''


def extract_bundle() -> Path:
    target = Path(tempfile.gettempdir()) / 'review_intelligence_render_bundle'
    marker = target / '.bundle_ready'
    if marker.exists():
        return target
    target.mkdir(parents=True, exist_ok=True)
    raw = base64.b64decode(BUNDLE_B64)
    with zipfile.ZipFile(io.BytesIO(raw)) as archive:
        archive.extractall(target)
    marker.write_text('ok', encoding='utf-8')
    return target


def main() -> None:
    root = extract_bundle()
    backend = root / 'backend'
    sys.path.insert(0, str(backend))
    os.chdir(root)
    runpy.run_path(str(backend / 'server.py'), run_name='__main__')


if __name__ == '__main__':
    main()
